"use client";

import { useRef, useEffect, useState } from "react";
import { Planet, planets } from "./data";

interface SolarSystemCanvasProps {
  onPlanetSelect: (planet: Planet | null) => void;
  selectedPlanetId: string | null;
  speedMultiplier: number;
}

export function SolarSystemCanvas({
  onPlanetSelect,
  selectedPlanetId,
  speedMultiplier,
}: SolarSystemCanvasProps) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const [hoveredPlanet, setHoveredPlanet] = useState<string | null>(null);

  // Internal state for planet angles to maintain continuity
  const planetAngles = useRef<{ [key: string]: number }>({});

  useEffect(() => {
    // Initialize angles
    planets.forEach((p) => {
      if (planetAngles.current[p.id] === undefined) {
        planetAngles.current[p.id] = Math.random() * Math.PI * 2;
      }
    });
  }, []);

  useEffect(() => {
    const canvas = canvasRef.current;
    const container = containerRef.current;
    if (!canvas || !container) return;

    const ctx = canvas.getContext("2d");
    if (!ctx) return;

    let animationFrameId: number;
    let width = 0;
    let height = 0;
    let centerX = 0;
    let centerY = 0;
    let scale = 1;

    // Starfield
    const stars: { x: number; y: number; size: number; opacity: number }[] = [];
    const initStars = () => {
      stars.length = 0;
      for (let i = 0; i < 200; i++) {
        stars.push({
          x: Math.random() * width,
          y: Math.random() * height,
          size: Math.random() * 2,
          opacity: Math.random(),
        });
      }
    };

    const resize = () => {
      width = container.clientWidth;
      height = container.clientHeight;
      canvas.width = width;
      canvas.height = height;
      centerX = width / 2;
      centerY = height / 2;
      
      // Responsive scale: Fit outer orbit (Neptune = 480) within screen
      // Add padding
      const minDim = Math.min(width, height);
      scale = (minDim / 2) / 550; 
      
      initStars();
    };

    window.addEventListener("resize", resize);
    resize();

    const draw = () => {
      ctx.clearRect(0, 0, width, height);

      // Draw Stars
      ctx.fillStyle = "white";
      stars.forEach((star) => {
        ctx.globalAlpha = star.opacity;
        ctx.beginPath();
        ctx.arc(star.x, star.y, star.size, 0, Math.PI * 2);
        ctx.fill();
      });
      ctx.globalAlpha = 1;

      // Draw Sun
      const sunGradient = ctx.createRadialGradient(centerX, centerY, 0, centerX, centerY, 40 * scale);
      sunGradient.addColorStop(0, "#FDB813");
      sunGradient.addColorStop(0.4, "#F57C00");
      sunGradient.addColorStop(1, "transparent");
      
      ctx.fillStyle = sunGradient;
      ctx.beginPath();
      ctx.arc(centerX, centerY, 40 * scale, 0, Math.PI * 2);
      ctx.fill();
      
      // Sun Core
      ctx.fillStyle = "#FFFDE7";
      ctx.beginPath();
      ctx.arc(centerX, centerY, 15 * scale, 0, Math.PI * 2);
      ctx.fill();

      // Draw Planets and Orbits
      planets.forEach((planet) => {
        const radius = planet.orbitRadius * scale;
        
        // Update Angle
        if (speedMultiplier > 0) {
            planetAngles.current[planet.id] += (planet.speed * 0.002 * speedMultiplier);
        }
        const angle = planetAngles.current[planet.id];

        // Draw Orbit
        ctx.beginPath();
        ctx.strokeStyle = selectedPlanetId === planet.id 
          ? "rgba(255, 255, 255, 0.5)" 
          : "rgba(255, 255, 255, 0.1)";
        ctx.lineWidth = selectedPlanetId === planet.id ? 2 : 1;
        ctx.arc(centerX, centerY, radius, 0, Math.PI * 2);
        ctx.stroke();

        // Calculate Position
        const x = centerX + Math.cos(angle) * radius;
        const y = centerY + Math.sin(angle) * radius;

        // Draw Planet
        const planetSize = Math.max(planet.size * scale, 4); // Minimum visible size
        
        // Shadow/Glow if hovered or selected
        if (hoveredPlanet === planet.id || selectedPlanetId === planet.id) {
          ctx.shadowColor = planet.color;
          ctx.shadowBlur = 15;
        } else {
          ctx.shadowBlur = 0;
        }

        ctx.fillStyle = planet.color;
        ctx.beginPath();
        ctx.arc(x, y, planetSize, 0, Math.PI * 2);
        ctx.fill();
        ctx.shadowBlur = 0; // Reset

        // Rings for Saturn
        if (planet.id === "saturn") {
            ctx.beginPath();
            ctx.strokeStyle = "rgba(200, 180, 150, 0.6)";
            ctx.lineWidth = 3 * scale;
            ctx.ellipse(x, y, planetSize * 2.5, planetSize * 0.8, angle + Math.PI/4, 0, Math.PI * 2);
            ctx.stroke();
        }

        // Label if hovered
        if (hoveredPlanet === planet.id || selectedPlanetId === planet.id) {
            ctx.fillStyle = "white";
            ctx.font = "12px monospace";
            ctx.textAlign = "center";
            ctx.fillText(planet.name, x, y - planetSize - 10);
        }
      });

      animationFrameId = requestAnimationFrame(draw);
    };

    draw();

    return () => {
      window.removeEventListener("resize", resize);
      cancelAnimationFrame(animationFrameId);
    };
  }, [speedMultiplier, selectedPlanetId, hoveredPlanet]);

  // Handle Interactions
  const handleMouseMove = (e: React.MouseEvent<HTMLCanvasElement>) => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const rect = canvas.getBoundingClientRect();
    const mx = e.clientX - rect.left;
    const my = e.clientY - rect.top;

    const width = canvas.width;
    const height = canvas.height;
    const centerX = width / 2;
    const centerY = height / 2;
    const minDim = Math.min(width, height);
    const scale = (minDim / 2) / 550;

    let found = null;

    // Check collision with planets (reverse order to check outer first, though barely matters here)
    for (const planet of planets) {
        const radius = planet.orbitRadius * scale;
        const angle = planetAngles.current[planet.id];
        const px = centerX + Math.cos(angle) * radius;
        const py = centerY + Math.sin(angle) * radius;
        const pSize = Math.max(planet.size * scale, 4) + 10; // Hitbox padding

        const dist = Math.sqrt((mx - px) ** 2 + (my - py) ** 2);
        if (dist < pSize) {
            found = planet.id;
            break;
        }
    }
    
    setHoveredPlanet(found);
    canvas.style.cursor = found ? "pointer" : "default";
  };

  const handleClick = () => {
      if (hoveredPlanet) {
          const planet = planets.find(p => p.id === hoveredPlanet);
          if (planet) onPlanetSelect(planet);
      } else {
          onPlanetSelect(null); // Deselect on clicking empty space
      }
  };

  return (
    <div ref={containerRef} className="absolute inset-0 w-full h-full bg-black">
      <canvas
        ref={canvasRef}
        className="block touch-none"
        onMouseMove={handleMouseMove}
        onClick={handleClick}
      />
    </div>
  );
}
