"use client";

import { useState, useEffect } from "react";
import { SolarSystemCanvas } from "@/components/solar-quest/SolarSystemCanvas";
import { GameOverlay } from "@/components/solar-quest/GameOverlay";
import { Planet, missions } from "@/components/solar-quest/data";
import { motion } from "framer-motion";

export default function SolarQuestPage() {
  const [selectedPlanet, setSelectedPlanet] = useState<Planet | null>(null);
  const [speed, setSpeed] = useState(1);
  const [isLoaded, setIsLoaded] = useState(false);

  // Derived game state for mission checking
  const gameState = {
    selectedPlanet: selectedPlanet?.id || null,
    speed,
  };

  useEffect(() => {
    // Simulate asset loading
    const timer = setTimeout(() => setIsLoaded(true), 1000);
    return () => clearTimeout(timer);
  }, []);

  const handlePlanetSelect = (planet: Planet | null) => {
    setSelectedPlanet(planet);
    // Pause game when inspecting a planet
    if (planet) {
        setSpeed(0);
    } else {
        setSpeed(1);
    }
  };

  const handleCloseDetails = () => {
    setSelectedPlanet(null);
    setSpeed(1);
  };

  return (
    <main className="relative w-full h-screen bg-black overflow-hidden">
      {/* Loading Screen */}
      <motion.div
        initial={{ opacity: 1 }}
        animate={{ opacity: isLoaded ? 0 : 1 }}
        pointerEvents={isLoaded ? "none" : "auto"}
        transition={{ duration: 1 }}
        className="absolute inset-0 z-50 flex flex-col items-center justify-center bg-black"
      >
        <div className="w-16 h-16 border-4 border-accent border-t-transparent rounded-full animate-spin mb-4" />
        <p className="font-mono text-accent text-sm tracking-[0.5em] uppercase animate-pulse">Initializing Systems...</p>
      </motion.div>

      {/* Game Layer */}
      <div className="absolute inset-0 z-0">
        <SolarSystemCanvas 
            onPlanetSelect={handlePlanetSelect}
            selectedPlanetId={selectedPlanet?.id || null}
            speedMultiplier={speed}
        />
      </div>

      {/* UI Layer */}
      <GameOverlay 
        selectedPlanet={selectedPlanet}
        missions={missions}
        gameState={gameState}
        speed={speed}
        setSpeed={setSpeed}
        onCloseDetails={handleCloseDetails}
      />
      
      {/* Ambient Audio (Optional placeholder) */}
      {/* <audio loop autoPlay muted={false} src="/sounds/space-ambient.mp3" /> */}
    </main>
  );
}
