"use client";

import { motion, AnimatePresence } from "framer-motion";
import { Planet, Mission } from "./data";
import { X, Play, Pause, FastForward, Info, Trophy, ArrowLeft, CheckCircle } from "lucide-react";
import Link from "next/link";

interface GameOverlayProps {
  selectedPlanet: Planet | null;
  missions: Mission[];
  gameState: any; // For mission checking
  speed: number;
  setSpeed: (speed: number) => void;
  onCloseDetails: () => void;
}

export function GameOverlay({
  selectedPlanet,
  missions,
  gameState,
  speed,
  setSpeed,
  onCloseDetails,
}: GameOverlayProps) {
  
  // Calculate completed missions
  const completedMissions = missions.filter(m => m.condition(gameState)).length;
  const progress = (completedMissions / missions.length) * 100;

  return (
    <div className="absolute inset-0 pointer-events-none flex flex-col justify-between p-6 md:p-8 z-10 overflow-hidden">
      
      {/* Top Bar */}
      <div className="flex justify-between items-start pointer-events-auto">
        <div className="flex flex-col gap-2">
            <Link href="/">
                <button className="flex items-center gap-2 text-white/70 hover:text-accent transition-colors group">
                    <ArrowLeft className="w-5 h-5 group-hover:-translate-x-1 transition-transform" />
                    <span className="font-mono text-sm tracking-widest uppercase">Abort Mission</span>
                </button>
            </Link>
            <h1 className="text-3xl md:text-5xl font-heading font-bold text-white uppercase tracking-tight mt-2">
                Solar <span className="text-transparent bg-clip-text bg-gradient-to-r from-accent to-purple-500">Quest</span>
            </h1>
        </div>

        {/* Mission HUD */}
        <div className="bg-black/40 backdrop-blur-md border border-white/10 rounded-xl p-4 w-64 md:w-80">
            <div className="flex items-center justify-between mb-2">
                <span className="text-xs font-mono text-accent uppercase tracking-widest flex items-center gap-2">
                    <Trophy className="w-3 h-3" /> Mission Status
                </span>
                <span className="text-xs text-white/70">{completedMissions}/{missions.length}</span>
            </div>
            {/* Progress Bar */}
            <div className="w-full h-1 bg-white/10 rounded-full mb-4 overflow-hidden">
                <motion.div 
                    className="h-full bg-accent"
                    initial={{ width: 0 }}
                    animate={{ width: `${progress}%` }}
                />
            </div>
            
            <div className="space-y-2 max-h-32 overflow-y-auto pr-2 custom-scrollbar">
                {missions.map(mission => {
                    const isCompleted = mission.condition(gameState);
                    return (
                        <div key={mission.id} className={`flex items-start gap-2 text-xs ${isCompleted ? 'text-green-400' : 'text-white/50'}`}>
                            {isCompleted ? <CheckCircle className="w-3 h-3 mt-0.5 shrink-0" /> : <div className="w-3 h-3 border border-current rounded-full mt-0.5 shrink-0" />}
                            <div>
                                <p className={`font-bold ${isCompleted && 'line-through opacity-70'}`}>{mission.title}</p>
                                <p className="opacity-70">{mission.description}</p>
                            </div>
                        </div>
                    );
                })}
            </div>
        </div>
      </div>

      {/* Bottom Bar: Controls */}
      <div className="flex justify-center pointer-events-auto">
         <div className="bg-black/40 backdrop-blur-md border border-white/10 rounded-full px-6 py-3 flex items-center gap-6">
            <button 
                onClick={() => setSpeed(0)}
                className={`text-white hover:text-accent transition-colors ${speed === 0 ? 'text-accent' : ''}`}
            >
                <Pause className="w-5 h-5" />
            </button>
            <button 
                onClick={() => setSpeed(1)}
                className={`text-white hover:text-accent transition-colors ${speed === 1 ? 'text-accent' : ''}`}
            >
                <Play className="w-5 h-5" />
            </button>
            <button 
                onClick={() => setSpeed(5)}
                className={`text-white hover:text-accent transition-colors ${speed === 5 ? 'text-accent' : ''}`}
            >
                <FastForward className="w-5 h-5" />
            </button>
            
            <div className="w-px h-6 bg-white/20 mx-2" />
            
            <span className="text-xs font-mono text-white/50 uppercase tracking-widest">
                Time Dilation: {speed}x
            </span>
         </div>
      </div>

      {/* Planet Details Panel (Side) */}
      <AnimatePresence>
        {selectedPlanet && (
            <motion.div
                initial={{ x: "100%", opacity: 0 }}
                animate={{ x: 0, opacity: 1 }}
                exit={{ x: "100%", opacity: 0 }}
                transition={{ type: "spring", damping: 25, stiffness: 200 }}
                className="absolute right-0 top-0 bottom-0 w-full md:w-[400px] bg-black/80 backdrop-blur-xl border-l border-white/10 p-8 z-20 pointer-events-auto overflow-y-auto"
            >
                <button 
                    onClick={onCloseDetails}
                    className="absolute top-6 right-6 p-2 bg-white/5 hover:bg-white/10 rounded-full text-white transition-colors"
                >
                    <X className="w-5 h-5" />
                </button>

                <div className="mt-12">
                    <div className="w-20 h-20 rounded-full mb-6 shadow-[0_0_50px_rgba(0,0,0,0.5)]" style={{ backgroundColor: selectedPlanet.color }} />
                    
                    <h2 className="text-4xl font-heading font-bold text-white uppercase tracking-wide mb-2">
                        {selectedPlanet.name}
                    </h2>
                    <p className="text-white/60 text-lg mb-8 leading-relaxed">
                        {selectedPlanet.description}
                    </p>

                    <div className="space-y-6">
                        <div className="bg-white/5 rounded-xl p-5 border border-white/5">
                            <h3 className="text-xs font-mono text-accent uppercase tracking-widest mb-4 flex items-center gap-2">
                                <Info className="w-4 h-4" /> Planetary Data
                            </h3>
                            <div className="grid grid-cols-1 gap-4 text-sm">
                                <div>
                                    <span className="block text-white/40 mb-1">Mass</span>
                                    <span className="text-white font-mono">{selectedPlanet.details.mass}</span>
                                </div>
                                <div>
                                    <span className="block text-white/40 mb-1">Distance from Sun</span>
                                    <span className="text-white font-mono">{selectedPlanet.details.distance}</span>
                                </div>
                                <div>
                                    <span className="block text-white/40 mb-1">Rotation Period</span>
                                    <span className="text-white font-mono">{selectedPlanet.details.rotation}</span>
                                </div>
                            </div>
                        </div>

                        <div className="bg-white/5 rounded-xl p-5 border border-white/5">
                            <h3 className="text-xs font-mono text-purple-400 uppercase tracking-widest mb-4">
                                Habitability Assessment
                            </h3>
                            <p className="text-white/80 text-sm">
                                {selectedPlanet.details.habitability}
                            </p>
                        </div>

                        <div className="bg-gradient-to-br from-accent/10 to-transparent rounded-xl p-5 border border-accent/20">
                            <h3 className="text-xs font-mono text-accent uppercase tracking-widest mb-4">
                                In Simple Terms
                            </h3>
                            <p className="text-white/90 italic text-sm">
                                "{selectedPlanet.details.analogy}"
                            </p>
                        </div>
                    </div>
                </div>
            </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}
